"""Launch Interceptor Program decision logic."""

from __future__ import annotations

import math
from decimal import Decimal, ROUND_HALF_UP
from typing import Dict, List, Sequence, Tuple


def realcompare(a: float, b: float) -> str:
    """Compare two reals using six significant digits.

    Returns "LT", "EQ", or "GT".
    """

    da = Decimal(str(a))
    db = Decimal(str(b))
    if da.is_zero() and db.is_zero():
        return "EQ"
    if da.is_zero():
        return "LT" if db > 0 else "GT"
    if db.is_zero():
        return "GT" if da > 0 else "LT"

    def round_sig(d: Decimal, sig: int = 6) -> Decimal:
        if d.is_zero():
            return Decimal(0)
        exp = d.adjusted()
        quant = Decimal(f"1e{exp - sig + 1}")
        return d.quantize(quant, rounding=ROUND_HALF_UP)

    ra = round_sig(da)
    rb = round_sig(db)
    if ra < rb:
        return "LT"
    if ra > rb:
        return "GT"
    return "EQ"


def _cmp_lt(a: float, b: float) -> bool:
    return realcompare(a, b) == "LT"


def _cmp_gt(a: float, b: float) -> bool:
    return realcompare(a, b) == "GT"


def _cmp_eq(a: float, b: float) -> bool:
    return realcompare(a, b) == "EQ"


def _ge_zero(a: float) -> bool:
    return realcompare(a, 0.0) in {"EQ", "GT"}


def _le_zero(a: float) -> bool:
    return realcompare(a, 0.0) in {"EQ", "LT"}


def _dist2(ax: float, ay: float, bx: float, by: float) -> float:
    dx = ax - bx
    dy = ay - by
    return dx * dx + dy * dy


def _dist(ax: float, ay: float, bx: float, by: float) -> float:
    return math.hypot(ax - bx, ay - by)


def _area2(ax: float, ay: float, bx: float, by: float, cx: float, cy: float) -> float:
    return abs((bx - ax) * (cy - ay) - (cx - ax) * (by - ay))


def _triangle_area(ax: float, ay: float, bx: float, by: float, cx: float, cy: float) -> float:
    return 0.5 * _area2(ax, ay, bx, by, cx, cy)


def _quadrant(x: float, y: float) -> int:
    if _ge_zero(x) and _ge_zero(y):
        return 1
    if _le_zero(x) and _ge_zero(y):
        return 2
    if _le_zero(x) and _le_zero(y):
        return 3
    return 4


def _angle_small(ax: float, ay: float, bx: float, by: float, cx: float, cy: float) -> float | None:
    """Return the smaller angle ABC in radians, or None if undefined."""

    v1x = ax - bx
    v1y = ay - by
    v2x = cx - bx
    v2y = cy - by
    if _cmp_eq(v1x, 0.0) and _cmp_eq(v1y, 0.0):
        return None
    if _cmp_eq(v2x, 0.0) and _cmp_eq(v2y, 0.0):
        return None
    n1 = math.hypot(v1x, v1y)
    n2 = math.hypot(v2x, v2y)
    if realcompare(n1, 0.0) == "EQ" or realcompare(n2, 0.0) == "EQ":
        return None
    cos_theta = (v1x * v2x + v1y * v2y) / (n1 * n2)
    cos_theta = max(-1.0, min(1.0, cos_theta))
    return math.acos(cos_theta)


def _min_circle_radius_for_three(
    ax: float,
    ay: float,
    bx: float,
    by: float,
    cx: float,
    cy: float,
) -> float:
    """Return the minimum enclosing circle radius for three points."""

    ab = _dist(ax, ay, bx, by)
    bc = _dist(bx, by, cx, cy)
    ca = _dist(cx, cy, ax, ay)

    ab2 = ab * ab
    bc2 = bc * bc
    ca2 = ca * ca

    # If the triangle is right or obtuse, the minimum enclosing circle
    # has diameter equal to the longest side.
    if (
        realcompare(ab2 + bc2, ca2) in {"LT", "EQ"}
        or realcompare(ab2 + ca2, bc2) in {"LT", "EQ"}
        or realcompare(bc2 + ca2, ab2) in {"LT", "EQ"}
    ):
        return max(ab, bc, ca) / 2.0

    area = _triangle_area(ax, ay, bx, by, cx, cy)
    if realcompare(area, 0.0) == "EQ":
        return max(ab, bc, ca) / 2.0
    return (ab * bc * ca) / (4.0 * area)


def _three_points_fit_in_circle_radius(
    ax: float,
    ay: float,
    bx: float,
    by: float,
    cx: float,
    cy: float,
    radius: float,
) -> bool:
    return realcompare(_min_circle_radius_for_three(ax, ay, bx, by, cx, cy), radius) in {"LT", "EQ"}


def decide(
    numpoints: int,
    x: Sequence[float],
    y: Sequence[float],
    parameters: Dict[str, float | int],
    lcm: Sequence[Sequence[str]],
    pum_diag: Sequence[bool],
) -> Tuple[List[bool], List[List[bool]], List[bool], bool]:
    """Behaviorally equivalent implementation of DECIDE."""

    length1 = float(parameters["LENGTH1"])
    radius1 = float(parameters["RADIUS1"])
    epsilon = float(parameters["EPSILON"])
    area1 = float(parameters["AREA1"])
    q_pts = int(parameters["Q_PTS"])
    quads = int(parameters["QUADS"])
    dist = float(parameters["DIST"])
    n_pts = int(parameters["N_PTS"])
    k_pts = int(parameters["K_PTS"])
    a_pts = int(parameters["A_PTS"])
    b_pts = int(parameters["B_PTS"])
    c_pts = int(parameters["C_PTS"])
    d_pts = int(parameters["D_PTS"])
    e_pts = int(parameters["E_PTS"])
    f_pts = int(parameters["F_PTS"])
    g_pts = int(parameters["G_PTS"])
    length2 = float(parameters["LENGTH2"])
    radius2 = float(parameters["RADIUS2"])
    area2 = float(parameters["AREA2"])

    cmv = [False] * 15

    # LIC 1
    cmv[0] = any(_cmp_gt(_dist(x[i], y[i], x[i + 1], y[i + 1]), length1) for i in range(numpoints - 1))

    # LIC 2
    cmv[1] = any(
        not _three_points_fit_in_circle_radius(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2], radius1)
        for i in range(numpoints - 2)
    )

    # LIC 3
    cmv[2] = False
    for i in range(numpoints - 2):
        angle = _angle_small(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2])
        if angle is None:
            continue
        if _cmp_lt(angle, math.pi - epsilon) or _cmp_gt(angle, math.pi + epsilon):
            cmv[2] = True
            break

    # LIC 4
    cmv[3] = any(
        _cmp_gt(_triangle_area(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2]), area1)
        for i in range(numpoints - 2)
    )

    # LIC 5
    cmv[4] = False
    if q_pts <= numpoints:
        for start in range(numpoints - q_pts + 1):
            quadrants = set(_quadrant(x[i], y[i]) for i in range(start, start + q_pts))
            if len(quadrants) > quads:
                cmv[4] = True
                break

    # LIC 6
    cmv[5] = any(_cmp_lt(x[i + 1], x[i]) for i in range(numpoints - 1))

    # LIC 7
    cmv[6] = False
    if n_pts <= numpoints:
        for start in range(numpoints - n_pts + 1):
            end = start + n_pts - 1
            if _cmp_eq(x[start], x[end]) and _cmp_eq(y[start], y[end]):
                for j in range(start + 1, end):
                    if _cmp_gt(_dist(x[start], y[start], x[j], y[j]), dist):
                        cmv[6] = True
                        break
            else:
                ax, ay = x[start], y[start]
                bx, by = x[end], y[end]
                dx = bx - ax
                dy = by - ay
                denom = math.hypot(dx, dy)
                for j in range(start + 1, end):
                    num = abs(dx * (ay - y[j]) - (ax - x[j]) * dy)
                    d = num / denom if realcompare(denom, 0.0) != "EQ" else _dist(ax, ay, x[j], y[j])
                    if _cmp_gt(d, dist):
                        cmv[6] = True
                        break
            if cmv[6]:
                break

    # LIC 8
    cmv[7] = any(_cmp_gt(_dist(x[i], y[i], x[i + k_pts + 1], y[i + k_pts + 1]), length1) for i in range(numpoints - k_pts - 1))

    # LIC 9
    cmv[8] = False
    if a_pts + b_pts <= numpoints - 3:
        for start in range(numpoints - (a_pts + b_pts + 2)):
            i1 = start
            i2 = start + a_pts + 1
            i3 = start + a_pts + b_pts + 2
            if not _three_points_fit_in_circle_radius(x[i1], y[i1], x[i2], y[i2], x[i3], y[i3], radius1):
                cmv[8] = True
                break

    # LIC 10
    cmv[9] = False
    if c_pts + d_pts <= numpoints - 3:
        for start in range(numpoints - (c_pts + d_pts + 2)):
            i1 = start
            i2 = start + c_pts + 1
            i3 = start + c_pts + d_pts + 2
            angle = _angle_small(x[i1], y[i1], x[i2], y[i2], x[i3], y[i3])
            if angle is None:
                continue
            if _cmp_lt(angle, math.pi - epsilon) or _cmp_gt(angle, math.pi + epsilon):
                cmv[9] = True
                break

    # LIC 11
    cmv[10] = False
    if e_pts + f_pts <= numpoints - 3:
        for start in range(numpoints - (e_pts + f_pts + 2)):
            i1 = start
            i2 = start + e_pts + 1
            i3 = start + e_pts + f_pts + 2
            if _cmp_gt(_triangle_area(x[i1], y[i1], x[i2], y[i2], x[i3], y[i3]), area1):
                cmv[10] = True
                break

    # LIC 12
    cmv[11] = any(_cmp_lt(x[i + g_pts + 1], x[i]) for i in range(numpoints - g_pts - 1))

    # LIC 13
    gt_len1 = False
    lt_len2 = False
    if numpoints >= 3:
        for i in range(numpoints - k_pts - 1):
            d = _dist(x[i], y[i], x[i + k_pts + 1], y[i + k_pts + 1])
            if _cmp_gt(d, length1):
                gt_len1 = True
            if _cmp_lt(d, length2):
                lt_len2 = True
            if gt_len1 and lt_len2:
                break
    cmv[12] = gt_len1 and lt_len2

    # LIC 14
    gt_r1 = False
    le_r2 = False
    if a_pts + b_pts <= numpoints - 3:
        for start in range(numpoints - (a_pts + b_pts + 2)):
            i1 = start
            i2 = start + a_pts + 1
            i3 = start + a_pts + b_pts + 2
            fit_r1 = _three_points_fit_in_circle_radius(x[i1], y[i1], x[i2], y[i2], x[i3], y[i3], radius1)
            fit_r2 = _three_points_fit_in_circle_radius(x[i1], y[i1], x[i2], y[i2], x[i3], y[i3], radius2)
            if not fit_r1:
                gt_r1 = True
            if fit_r2:
                le_r2 = True
            if gt_r1 and le_r2:
                break
    cmv[13] = gt_r1 and le_r2

    # LIC 15
    gt_a1 = False
    lt_a2 = False
    if e_pts + f_pts <= numpoints - 3:
        for start in range(numpoints - (e_pts + f_pts + 2)):
            i1 = start
            i2 = start + e_pts + 1
            i3 = start + e_pts + f_pts + 2
            area = _triangle_area(x[i1], y[i1], x[i2], y[i2], x[i3], y[i3])
            if _cmp_gt(area, area1):
                gt_a1 = True
            if _cmp_lt(area, area2):
                lt_a2 = True
            if gt_a1 and lt_a2:
                break
    cmv[14] = gt_a1 and lt_a2

    pum = [[False] * 15 for _ in range(15)]
    for i in range(15):
        pum[i][i] = bool(pum_diag[i])
    for i in range(15):
        for j in range(i + 1, 15):
            connector = lcm[i][j]
            if connector == "NOTUSED":
                value = True
            elif connector == "ANDD":
                value = cmv[i] and cmv[j]
            elif connector == "ORR":
                value = cmv[i] or cmv[j]
            else:
                raise ValueError(f"Invalid LCM connector: {connector!r}")
            pum[i][j] = value
            pum[j][i] = value

    fuv = [False] * 15
    for i in range(15):
        fuv[i] = (not pum[i][i]) or all(pum[i][j] for j in range(15))

    launch = all(fuv)
    return cmv, pum, fuv, launch
